import pandas as pd
from sklearn.feature_extraction.text import TfidfVectorizer
from sklearn.model_selection import train_test_split
from sklearn.linear_model import LogisticRegression
from flask import Flask, request, jsonify

app = Flask(__name__)

# Load dataset (assuming it's in a CSV file)
df = pd.read_csv('email_data.csv')

# Split data into training and testing sets
X_train, X_test, y_train, y_test = train_test_split(df['text'], df['spam'], test_size=0.2, random_state=42)

# Create TF-IDF vectorizer
vectorizer = TfidfVectorizer(stop_words='english')

# Fit the vectorizer to the training data and transform both sets
X_train_count = vectorizer.fit_transform(X_train)
y_train = y_train.map({0: 0, 1: 1})

# Train logistic regression model on training set
model = LogisticRegression()
model.fit(X_train_count, y_train)

@app.route('/predict', methods=['POST'])
def predict():
    data = request.json['text']
    count = vectorizer.transform([data])
    prediction = model.predict(count)
    return jsonify({'spam_probability': float(prediction[0])})

if __name__ == '__main__':
    app.run(debug=True)